17	// RBTDRE — case execution engine for theurge
18	
19	use std::path::Path;
20	use std::path::PathBuf;
21	
22	// ── Verdict ────────────────────────────────────────────────────
23	
24	/// Verdict from a single test case execution.
25	pub enum rbtdre_Verdict {
26	    Pass,
27	    Fail(String),
28	    Skip(String),
29	}
30	
31	// ── Disposition ────────────────────────────────────────────────
32	
33	/// Fixture disposition controls per-fixture mode policy at the engine layer.
34	///
35	/// `Independent` — cases are self-contained; suite-order is informational. Engine
36	/// permits keep-going mode for surveying.
37	///
38	/// `StateProgressing` — case N's success establishes preconditions for case N+1.
39	/// Engine refuses keep-going mode (a failed case leaves a broken precondition for
40	/// the next case, so continuing is incoherent). Fail-fast is forced.
41	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
42	pub enum rbtdre_Disposition {
43	    Independent,
44	    StateProgressing,
45	}
46	
47	/// Resolve the effective fail-fast bool from a disposition and a caller's
48	/// requested keep-going mode. Returns Err if the request is incompatible with
49	/// the disposition (StateProgressing + keep-going).
50	///
51	/// Centralizes the keep-going / fail-fast policy at the engine boundary so all
52	/// callers funnel through one place.
53	pub fn rbtdre_resolve_fail_fast(
54	    disposition: rbtdre_Disposition,
55	    keep_going_requested: bool,
56	) -> Result<bool, String> {
57	    match (disposition, keep_going_requested) {
58	        (rbtdre_Disposition::StateProgressing, true) => Err(
59	            "rbtd: keep-going mode refused for StateProgressing fixture — \
60	             a failed case leaves a broken precondition for the next case, \
61	             so continuing is incoherent. Run individual cases via the \
62	             SingleCase tabtarget if you want to survey."
63	                .to_string(),
64	        ),
65	        (rbtdre_Disposition::StateProgressing, false) => Ok(true),
66	        (rbtdre_Disposition::Independent, keep_going) => Ok(!keep_going),
67	    }
68	}
69	
70	// ── Case and Section ───────────────────────────────────────────
71	
72	/// A named test case with a function that receives its isolated temp directory.
73	/// The `name` field holds the raw stringified function name (from the `case!` macro).
74	pub struct rbtdre_Case {
75	    pub name: &'static str,
76	    pub func: fn(&Path) -> rbtdre_Verdict,
77	}
78	
79	/// A named group of test cases, printed as a section header during execution.
80	pub struct rbtdre_Section {
81	    pub name: &'static str,
82	    pub cases: &'static [rbtdre_Case],
83	}
84	
85	/// A complete fixture definition — name, disposition, optional setup/teardown
86	/// hooks, and section array. All fixture-level metadata in one place; replaces
87	/// the prior side-channel matchers (sections_for_fixture, fixture_disposition,
88	/// needs_charge, needs_readiness_delay) keyed off the fixture name string.
89	///
90	/// `setup` runs before any cases. Failure aborts the fixture; cases do not run;
91	/// `teardown` still runs (finally-shaped) for any partial-state cleanup.
92	///
93	/// `teardown` runs unconditionally after cases regardless of case verdicts or
94	/// setup outcome. Errors are surfaced as warnings — teardown is best-effort.
95	///
96	/// Both hooks access invocation context via the thread-local established by
97	/// `rbtdrc_set_context` before `rbtdre_run_fixture` is called.
98	pub struct rbtdre_Fixture {
99	    pub name: &'static str,
100	    pub disposition: rbtdre_Disposition,
101	    pub setup: Option<fn() -> Result<(), String>>,
102	    pub teardown: Option<fn()>,
103	    pub sections: &'static [rbtdre_Section],
104	}
105	
106	/// Case registration macro. Derives case name from function name via `stringify!`.
107	/// Compiler enforces uniqueness — duplicate function names won't compile.
108	#[macro_export]
109	macro_rules! case {
110	    ($func:path) => {
111	        $crate::rbtdre_engine::rbtdre_Case {
112	            name: stringify!($func),
113	            func: $func,
114	        }
115	    };
116	}
117	
118	// ── Colors ─────────────────────────────────────────────────────
119	
120	/// Terminal color codes, empty strings when color is disabled.
121	pub struct rbtdre_Colors {
122	    pub green: &'static str,
123	    pub red: &'static str,
124	    pub yellow: &'static str,
125	    pub white: &'static str,
126	    pub reset: &'static str,
127	}
128	
129	/// Detect terminal color support from TERM environment variable.
130	pub fn rbtdre_detect_colors() -> rbtdre_Colors {
131	    match std::env::var("TERM") {
132	        Ok(term) if !term.is_empty() && term != "dumb" => rbtdre_Colors {
133	            green: "\x1b[1;32m",
134	            red: "\x1b[1;31m",
135	            yellow: "\x1b[1;33m",
136	            white: "\x1b[1;37m",
137	            reset: "\x1b[0m",
138	        },
139	        _ => rbtdre_Colors {
140	            green: "",
141	            red: "",
142	            yellow: "",
143	            white: "",
144	            reset: "",
145	        },
146	    }
147	}
148	
149	// ── Trace ──────────────────────────────────────────────────────
150	
151	/// Write verdict and detail to a trace file in the case temp directory.
152	fn rbtdre_write_trace(case_dir: &Path, display_name: &str, verdict: &rbtdre_Verdict) {
153	    let content = match verdict {
154	        rbtdre_Verdict::Pass => format!("PASSED: {}\n", display_name),
155	        rbtdre_Verdict::Fail(detail) => format!("FAILED: {}\n\n{}\n", display_name, detail),
156	        rbtdre_Verdict::Skip(reason) => {
157	            format!("SKIPPED: {}\n\nReason: {}\n", display_name, reason)
158	        }
159	    };
160	    let _ = std::fs::write(case_dir.join("trace.txt"), content);
161	}
162	
163	// ── Dispatch ───────────────────────────────────────────────────
164	
165	/// Aggregate results from running sections.
166	pub struct rbtdre_RunResult {
167	    pub passed: usize,
168	    pub failed: usize,
169	    pub skipped: usize,
170	    pub temp_dir: PathBuf,
171	}
172	
173	/// Run all sections sequentially, dispatching each case with per-case temp dir isolation.
174	pub fn rbtdre_run_sections(
175	    sections: &[rbtdre_Section],
176	    colors: &rbtdre_Colors,
177	    fail_fast: bool,
178	    root_temp: &Path,
179	) -> Result<rbtdre_RunResult, String> {
180	    let mut passed = 0usize;
181	    let mut failed = 0usize;
182	    let mut skipped = 0usize;
183	
184	    'outer: for section in sections {
185	        eprintln!(
186	            "\n{}--- {} ---{}",
187	            colors.white, section.name, colors.reset
188	        );
189	
190	        for case in section.cases {
191	            let case_dir = root_temp.join(case.name);
192	            std::fs::create_dir_all(&case_dir).map_err(|e| {
193	                format!("rbtd: failed to create case dir '{}': {}", case.name, e)
194	            })?;
195	
196	            let verdict = (case.func)(&case_dir);
197	            rbtdre_write_trace(&case_dir, case.name, &verdict);
198	
199	            match &verdict {
200	                rbtdre_Verdict::Pass => {
201	                    eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
202	                    passed += 1;
203	                }
204	                rbtdre_Verdict::Fail(_) => {
205	                    eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
206	                    failed += 1;
207	                    if fail_fast {
208	                        break 'outer;
209	                    }
210	                }
211	                rbtdre_Verdict::Skip(_) => {
212	                    eprintln!(
213	                        "{}SKIPPED:{} {}",
214	                        colors.yellow, colors.reset, case.name
215	                    );
216	                    skipped += 1;
217	                }
218	            }
219	        }
220	    }
221	
222	    Ok(rbtdre_RunResult {
223	        passed,
224	        failed,
225	        skipped,
226	        temp_dir: root_temp.to_path_buf(),
227	    })
228	}
229	
230	/// Print colored summary line and trace directory location.
231	pub fn rbtdre_print_summary(result: &rbtdre_RunResult, colors: &rbtdre_Colors) {
232	    let total = result.passed + result.failed + result.skipped;
233	    let (color, end_color) = if result.failed > 0 {
234	        (colors.red, colors.reset)
235	    } else {
236	        (colors.green, colors.reset)
237	    };
238	
239	    eprintln!(
240	        "\n{}{} passed, {} failed, {} skipped ({} total){}",
241	        color, result.passed, result.failed, result.skipped, total, end_color,
242	    );
243	    eprintln!("Trace dir: {}", result.temp_dir.display());
244	}
245	
246	// ── Single-case operations ───────────────────────────────────
247	
248	/// Find a case by name within sections.
249	pub fn rbtdre_find_case<'a>(
250	    sections: &'a [rbtdre_Section],
251	    target: &str,
252	) -> Option<&'a rbtdre_Case> {
253	    for section in sections {
254	        for case in section.cases {
255	            if case.name == target {
256	                return Some(case);
257	            }
258	        }
259	    }
260	    None
261	}
262	
263	/// List all cases grouped by section.
264	pub fn rbtdre_list_cases(sections: &[rbtdre_Section]) {
265	    for section in sections {
266	        eprintln!("\n--- {} ---", section.name);
267	        for case in section.cases {
268	            eprintln!("  {}", case.name);
269	        }
270	    }
271	}
272	
273	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
274	///
275	/// Expects the invocation context to already be installed in the thread-local
276	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
277	///
278	/// Setup failure short-circuits cases but still invokes teardown. Teardown
279	/// errors are surfaced as warnings via stderr; the function never panics on
280	/// teardown failure.
281	pub fn rbtdre_run_fixture(
282	    fixture: &'static rbtdre_Fixture,
283	    colors: &rbtdre_Colors,
284	    root_temp: &Path,
285	) -> Result<rbtdre_RunResult, String> {
286	    let setup_result = match fixture.setup {
287	        Some(f) => f(),
288	        None => Ok(()),
289	    };
290	
291	    let run_result = match setup_result {
292	        Ok(()) => {
293	            let fail_fast = rbtdre_resolve_fail_fast(fixture.disposition, false)
294	                .expect("disposition-default mode never fails policy resolution");
295	            rbtdre_run_sections(fixture.sections, colors, fail_fast, root_temp)
296	        }
297	        Err(msg) => Err(format!("rbtd: fixture '{}' setup failed: {}", fixture.name, msg)),
298	    };
299	
300	    if let Some(f) = fixture.teardown {
301	        f();
302	    }
303	
304	    run_result
305	}
306	
307	/// Run a single case without charge/quench lifecycle.
308	pub fn rbtdre_run_single_case(
309	    case: &rbtdre_Case,
310	    colors: &rbtdre_Colors,
311	    root_temp: &Path,
312	) -> Result<rbtdre_RunResult, String> {
313	    let case_dir = root_temp.join(case.name);
314	    std::fs::create_dir_all(&case_dir)
315	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
316	
317	    let verdict = (case.func)(&case_dir);
318	    rbtdre_write_trace(&case_dir, case.name, &verdict);
319	
320	    let (passed, failed, skipped) = match &verdict {
321	        rbtdre_Verdict::Pass => {
322	            eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
323	            (1, 0, 0)
324	        }
325	        rbtdre_Verdict::Fail(_) => {
326	            eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
327	            (0, 1, 0)
328	        }
329	        rbtdre_Verdict::Skip(_) => {
330	            eprintln!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
331	            (0, 0, 1)
332	        }
333	    };
334	
335	    Ok(rbtdre_RunResult {
336	        passed,
337	        failed,
338	        skipped,
339	        temp_dir: root_temp.to_path_buf(),
340	    })
341	}
