pub static RBTDRL_FIXTURE_PROGRESSING: rbtdre_Fixture = rbtdre_Fixture {
    name: RBTDRM_FIXTURE_CALIBRANT_PROGRESSING,
    disposition: rbtdre_Disposition::StateProgressing,
    setup: None,
    teardown: None,
    sections: RBTDRL_SECTIONS_PROGRESSING,
