pub static RBTDRL_FIXTURE_SENTINEL: rbtdre_Fixture = rbtdre_Fixture {
    name: RBTDRM_FIXTURE_CALIBRANT_SENTINEL,
    disposition: rbtdre_Disposition::Independent,
