37	/// Allocate a unique tempdir for a case under std::env::temp_dir.
38	/// Caller is responsible for cleanup.
39	fn rbtdtl_make_tempdir(label: &str) -> PathBuf {
40	    let pid = std::process::id();
41	    let nanos = std::time::SystemTime::now()
42	        .duration_since(std::time::UNIX_EPOCH)
43	        .map(|d| d.as_nanos())
44	        .unwrap_or(0);
45	    let dir = std::env::temp_dir().join(format!("rbtdtl-{}-{}-{}", label, pid, nanos));
