51	fn rbtdtl_run_case(fixture: &'static str, case_name: &str) -> (rbtdre_Verdict, PathBuf) {
52	    let fix = rbtdrc_lookup_fixture(fixture)
53	        .unwrap_or_else(|| panic!("fixture '{}' not registered", fixture));
54	    let case = rbtdre_find_case(fix.sections, case_name)
55	        .unwrap_or_else(|| panic!("case '{}' not found in fixture '{}'", case_name, fixture));
56	    let dir = rbtdtl_make_tempdir(case_name);
57	    let verdict = (case.func)(&dir);
58	    (verdict, dir)
