fn rbtdtl_failfast_fail_returns_fail() {
    let (verdict, dir) =
        rbtdtl_run_case(RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST, "rbtdrl_failfast_fail");
    rbtdtl_assert_fail_with(&verdict, "intra-section", "failfast_fail");
    let _ = std::fs::remove_dir_all(&dir);
