    );
    rbtdtl_assert_pass(&verdict, "not_reached_intra");
    assert!(
        dir.join(RBTDRL_SENTINEL_FILE).exists(),
        "intra not_reached must write sentinel when run"
    );
    let _ = std::fs::remove_dir_all(&dir);
