    if let Err(v) = rbtdrb_assert(&probe) {
        return v;
    }
    rbtdre_Verdict::Pass
}

fn rbtdrl_progressing_probe_err(_dir: &Path) -> rbtdre_Verdict {
    let probe = rbtdrb_Probe {
        name: "calibrant deterministic err",
        check: rbtdrl_probe_err,
